import asyncio, httpx, os, re, uvicorn, json
from datetime import datetime
from fastapi import FastAPI, Request
from fastapi.responses import HTMLResponse
from fastapi.middleware.cors import CORSMiddleware

app = FastAPI()
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])
OLLAMA_URL, LOG_DIR, client_holder = "http://127.0.0.1:11434", "/mnt/e/Synthesis_Logs", {}
if not os.path.exists(LOG_DIR): os.makedirs(LOG_DIR, exist_ok=True)

@app.on_event("startup")
async def startup(): client_holder["client"] = httpx.AsyncClient(timeout=120.0)

def deep_clean(text):
    text = re.sub(r'<think>.*?</think>', '', text, flags=re.DOTALL)
    text = re.sub(r'\\boxed\{(.*?)\}', r'\1', text).replace('**', '').replace('*', '').replace('\\', '')
    return '\n\n'.join(text.split('\n\n')[:2]).strip()[:650]

@app.post("/spark")
async def spark(request: Request):
    data = await request.json()
    p = "Generate one provocative, deep, one-sentence philosophical or technical question. No markdown."
    res = await client_holder["client"].post(f"{OLLAMA_URL}/api/generate", json={"model": data['model'], "stream": False, "prompt": p})
    return {"prompt": deep_clean(res.json()['response'])}

@app.post("/generate")
async def generate(request: Request):
    data = await request.json()
    res = await client_holder["client"].post(f"{OLLAMA_URL}/api/generate", json={"model": data['model'], "prompt": data['prompt'], "system": data['system'], "stream": False})
    return {"response": deep_clean(res.json()['response'])}

@app.get("/models")
async def models():
    res = await client_holder["client"].get(f"{OLLAMA_URL}/api/tags")
    return res.json()['models']

@app.get("/", response_class=HTMLResponse)
async def home():
    vault_data = ""
    if os.path.exists("vault.js"):
        with open("vault.js", "r") as f: vault_data = f.read()
    return HTMLResponse(content=HTML_CONTENT.replace("//VAULT_INJECTION_POINT//", vault_data))

HTML_CONTENT = r"""<!DOCTYPE html><html><head><title>AMBER v8.9.2</title><style>html,body{background:#000;color:#FFF;font-family:monospace;margin:0;padding:0;overflow:hidden;height:100%;}#header{height:40px;border-bottom:2px solid #FFB000;color:#FFB000;display:flex;justify-content:center;align-items:center;font-weight:bold;background:#080808;letter-spacing:2px;position:relative;}.header-side{position:absolute;left:20px;font-size:10px;color:#444;}#hud{position:absolute;right:20px;font-size:11px;display:flex;gap:15px;}.state-active{color:#00FFFF;animation:blink 1s infinite;}#arena{display:flex;height:calc(100vh - 230px);padding:15px;gap:15px;box-sizing:border-box;}.node-box{width:22%;display:flex;flex-direction:column;align-items:center;border:1px solid #222;padding:15px;background:#030303;}#feed{flex-grow:1;width:56%;display:flex;flex-direction:column;border:2px solid #1a1a1a;background:#020202;overflow:hidden;position:relative;}#log{flex-grow:1;overflow-y:auto;padding:20px;scroll-behavior:smooth;}#splash,#recap{position:absolute;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.98);z-index:100;display:none;flex-direction:column;align-items:center;justify-content:center;text-align:center;border:2px solid #FFB000;padding:40px;}.amber-txt{color:#FFB000;font-weight:bold;letter-spacing:2px;text-transform:uppercase;margin-bottom:10px;font-size:16px;}.msg{margin-bottom:35px;border-bottom:1px solid #222;padding-bottom:15px;font-size:15px;line-height:1.6;color:#ddd;}.node-name{color:#FFB000;font-weight:bold;border-left:4px solid #FFB000;padding-left:12px;margin-bottom:10px;display:block;}pre.pixel-art{font-size:22px;line-height:1;color:#FFB000;margin:15px 0;height:140px;display:flex;align-items:center;justify-content:center;white-space:pre;background:#000;width:100%;}#control-deck{height:190px;background:#000;border-top:2px solid #FFB000;padding:10px 15px;display:grid;grid-template-columns:1.2fr 1.5fr 1.2fr;gap:15px;box-sizing:border-box;}input,textarea,select{background:#000;color:#FFB000;border:1px solid #222;padding:4px;font-family:monospace;font-size:11px;}button{background:#FFB000;color:#000;border:none;padding:10px;font-weight:bold;cursor:pointer;text-transform:uppercase;}@keyframes blink{0%,100%{opacity:1;}50%{opacity:0;}}</style></head><body onload="init()"><script>//VAULT_INJECTION_POINT//</script><div id="header"><span class="header-side">PC1 // STAINLESS // v8.9.2</span><span>[ AGENTIC SYNTHESIS ]</span><div id="hud"><span id="round-hud">ROUND: 00/00</span><span id="state-ui">[ STANDBY ]</span></div></div><div id="arena"><div class="node-box" id="pod-1"><div class="amber-txt" id="display-n1">AGENT_1</div><pre id="art-1" class="pixel-art"></pre><div id="think-1" style="color:#F00;display:none;animation:blink 1.5s infinite;">>> [ SIMULATING ]</div><div style="font-size:9px;color:#FF00FF;margin-top:auto;">VOICE: <span id="vname-1">---</span></div></div><div id="feed"><div id="splash"><div class="amber-txt" id="splash-roster">MATCHUP: PENDING</div><div id="splash-topic" style="color:#FFF;font-size:14px;margin:20px 0;">SIGNAL: READY</div><div style="width:300px;height:4px;background:#111;border:1px solid #222;"><div id="splash-bar" style="width:0%;height:100%;background:#FFB000;transition:width 10s linear;"></div></div></div><div id="recap"><div class="amber-txt">COMPLETE</div><button onclick="location.reload()">RELOAD</button></div><div id="log"></div></div><div class="node-box" id="pod-2"><div class="amber-txt" id="display-n2">AGENT_2</div><pre id="art-2" class="pixel-art"></pre><div id="think-2" style="color:#F00;display:none;animation:blink 1.5s infinite;">>> [ SIMULATING ]</div><div style="font-size:9px;color:#FF00FF;margin-top:auto;">VOICE: <span id="vname-2">---</span></div></div></div><div id="control-deck"><div style="display:flex;flex-direction:column;gap:3px;"><div style="display:flex;gap:2px;"><select id="s1-1" onchange="applyS(1,1)"><option value="">- ACADEMIC -</option></select><select id="s1-2" onchange="applyS(1,2)"><option value="">- CIVILIAN -</option></select><select id="s1-3" onchange="applyS(1,3)"><option value="">- FRINGE -</option></select></div><input type="text" id="n-1" placeholder="NAME"><select id="m-1"></select><textarea id="p-1" rows="2"></textarea></div><div style="text-align:center;"><div style="display:flex;gap:5px;margin-bottom:5px;"><button onclick="sparkAI()">⚡</button><input type="text" id="topic" placeholder="SIGNAL" style="flex-grow:1;"></div><select id="rounds-limit" style="width:100%;margin-bottom:5px;"><option value="1">1 ROUND</option><option value="2">2 ROUNDS</option><option value="3">3 ROUNDS</option><option value="4">4 ROUNDS</option><option value="5" selected>5 ROUNDS</option><option value="6">6 ROUNDS</option><option value="7">7 ROUNDS</option><option value="8">8 ROUNDS</option><option value="9">9 ROUNDS</option><option value="10">10 ROUNDS (MAX)</option></select><button onclick="runSynthesis()" style="width:100%;">IGNITE</button><button onclick="location.reload()" style="width:100%;margin-top:4px;background:#300;color:#F44;">HALT</button></div><div style="display:flex;flex-direction:column;gap:3px;"><div style="display:flex;gap:2px;"><select id="s2-1" onchange="applyS(2,1)"><option value="">- ACADEMIC -</option></select><select id="s2-2" onchange="applyS(2,2)"><option value="">- CIVILIAN -</option></select><select id="s2-3" onchange="applyS(2,3)"><option value="">- FRINGE -</option></select></div><input type="text" id="n-2" placeholder="NAME"><select id="m-2"></select><textarea id="p-2" rows="2"></textarea></div></div><script>let abortSignal=false,synth=window.speechSynthesis,voices=[],sessionBuffer=[];window.activeUtterance=null;function init(){fetchModels();const lv=()=>{voices=synth.getVoices();};lv();if(speechSynthesis.onvoiceschanged!==undefined)speechSynthesis.onvoiceschanged=lv;if(typeof VAULT !== 'undefined'){[1,2].forEach(i=>{populate(document.getElementById(`s${i}-1`),VAULT.academic);populate(document.getElementById(`s${i}-2`),VAULT.civilian);populate(document.getElementById(`s${i}-3`),VAULT.fringe);});}}function populate(s,d){Object.keys(d).sort().forEach(k=>{let o=document.createElement('option');o.value=k;o.innerText=k.toUpperCase();s.appendChild(o);});}function applyS(a,sn){const cats=["academic","civilian","fringe"],val=document.getElementById(`s${a}-${sn}`).value,data=VAULT[cats[sn-1]][val];if(!data)return;[1,2,3].forEach(s=>{if(s!==sn)document.getElementById(`s${a}-${s}`).value="";});document.getElementById(`n-${a}`).value=val;document.getElementById(`p-${a}`).value=data.p;document.getElementById(`display-n${a}`).innerText=val;document.getElementById(`art-${a}`).textContent=data.a;}async function fetchModels(){const res=await fetch('/models'),json=await res.json();[document.getElementById('m-1'),document.getElementById('m-2')].forEach(s=>{s.innerHTML="";json.forEach(m=>{let o=document.createElement('option');o.value=m.name;o.innerText=m.name.toUpperCase();s.appendChild(o);})});}async function sparkAI(){const m=document.getElementById('m-1').value,res=await fetch('/spark',{method:'POST',body:JSON.stringify({model:m})}),d=await res.json();document.getElementById('topic').value=d.prompt;}function getVoice(g){let t=voices.find(v=>v.lang.startsWith('en')&&(g==='male'?(v.name.includes('David')||v.name.includes('Mark')):(v.name.includes('Zira')||v.name.includes('Female'))));return t||voices[0];}async function runSynthesis(){abortSignal=false;sessionBuffer=[];synth.cancel();synth.resume();const rounds=parseInt(document.getElementById('rounds-limit').value),topic=document.getElementById('topic').value,n1=document.getElementById('n-1').value,n2=document.getElementById('n-2').value;document.getElementById('state-ui').innerText="[ ACTIVE ]";document.getElementById('state-ui').classList.add('state-active');document.getElementById('splash').style.display='flex';document.getElementById('splash-topic').innerText=`SIGNAL: ${topic}`;document.getElementById('splash-bar').style.width='100%';await new Promise(r=>setTimeout(r,10000));if(abortSignal)return;document.getElementById('splash').style.display='none';let last=topic;for(let i=1;i<=rounds;i++){if(abortSignal)break;document.getElementById('round-hud').innerText=`ROUND: ${i}/${rounds}`;const agents=[{id:1,n:n1,m:document.getElementById('m-1').value,p:document.getElementById('p-1').value,g:'male'},{id:2,n:n2,m:document.getElementById('m-2').value,p:document.getElementById('p-2').value,g:'female'}];for(const a of agents){if(abortSignal)break;document.getElementById(`think-${a.id}`).style.display='block';const r=await fetch('/generate',{method:'POST',body:JSON.stringify({prompt:last,system:`Role:${a.n}. Persona:${a.p}. Max 2 paragraphs.`,model:a.m})});const j=await r.json();last=j.response;sessionBuffer.push(`${a.n}:${last}`);document.getElementById(`think-${a.id}`).style.display='none';const msg=document.createElement('div');msg.className='msg';msg.innerHTML=`<span class="node-name">${a.n}</span><span id="t-${i}-${a.id}"></span>`;document.getElementById('log').appendChild(msg);await new Promise(resolve=>{window.activeUtterance=new SpeechSynthesisUtterance(last);window.activeUtterance.voice=getVoice(a.g);document.getElementById(`vname-${a.id}`).innerText=window.activeUtterance.voice?window.activeUtterance.voice.name.split(' ')[0]:"---";let tyDone=false,safety=setTimeout(()=>{synth.cancel();resolve();},60000);let hb=setInterval(()=>synth.resume(),5000);window.activeUtterance.onend=()=>{if(tyDone){clearInterval(hb);clearTimeout(safety);setTimeout(resolve,4000);}};synth.speak(window.activeUtterance);let cIdx=0;const ty=setInterval(()=>{if(cIdx<last.length&&!abortSignal){document.getElementById(`t-${i}-${a.id}`).innerHTML+=last[cIdx];cIdx++;document.getElementById('log').scrollTop=document.getElementById('log').scrollHeight;}else{clearInterval(ty);tyDone=true;if(!synth.speaking)window.activeUtterance.onend();}},45);});}}document.getElementById('recap').style.display='flex';}</script></body></html>"""

if __name__ == "__main__":
    uvicorn.run(app, host="0.0.0.0", port=18789)

